const expected = env.get("TELEGRAM_WEBHOOK_SECRET");
const urlSecret = msg.req && msg.req.params && msg.req.params.secret;
const headerSecret = msg.req && msg.req.headers && msg.req.headers["x-telegram-bot-api-secret-token"];

if (!expected || urlSecret !== expected || headerSecret !== expected) {
    msg.statusCode = 403;
    msg.payload = { ok: false, error: "forbidden" };
    return [null, msg];
}

msg.telegramUpdate = msg.payload;
msg.statusCode = 200;
msg.payload = { ok: true };
return [msg, null];

const bot = global.get("birthdayBot");
const [outgoing, callbacks] = await bot.handleTelegramUpdate(msg, env, node);
return [...outgoing, ...callbacks];

const botToken = env.get("TELEGRAM_BOT_TOKEN");
const adminChatId = env.get("ADMIN_CHAT_ID");

if (!adminChatId) {
    node.warn("ADMIN_CHAT_ID не знайдено у файлі .env!");
    return null;
}

const errorMsg = msg.error ? msg.error.message : "Невідома помилка";
const sourceNode = (msg.error && msg.error.source) ? (msg.error.source.name || msg.error.source.id) : "Невідомий вузол";

msg.url = `https://api.telegram.org/bot${botToken}/sendMessage`;
msg.method = "POST";
msg.payload = {
    chat_id: adminChatId,
    text: `🚨 <b>Критична помилка в потоці!</b>\n\n<b>Де:</b> ${sourceNode}\n<b>Деталі:</b> <code>${errorMsg}</code>`,
    parse_mode: "HTML"
};

delete msg.headers;

return msg;

const response = msg.payload;

if (msg.statusCode === 429 || (response && response.error_code === 429)) {
    node.warn(`Telegram rate limit: retry after ${(response && response.parameters && response.parameters.retry_after) || 5}s`);
    return [null, null, msg];
}

if (!response || response.ok !== true) {
    msg.telegramApiError = {
        url: msg.url,
        method: msg.method,
        statusCode: msg.statusCode,
        response
    };

    node.warn(`Telegram API error: ${JSON.stringify(response)}`);
    return [null, msg, null];
}

msg.telegramApiResult = response.result;
return [msg, null, null];

const MAX_RETRIES = 3;
const retryCount = (msg._retryCount || 0) + 1;

if (retryCount > MAX_RETRIES) {
    node.warn(`Rate limit: max retries (${MAX_RETRIES}) reached for ${msg.url}. Dropping message.`);
    node.status({ fill: "red", shape: "dot", text: `Dropped after ${MAX_RETRIES} retries` });
    return null;
}

const retryAfter = (msg.payload && msg.payload.parameters && msg.payload.parameters.retry_after) || 5;

msg._retryCount = retryCount;
msg.delay = retryAfter * 1000;
msg.payload = msg._reqPayload;

node.status({ fill: "yellow", shape: "dot", text: `429 – retry ${retryCount}/${MAX_RETRIES} in ${retryAfter}s` });

return msg;
